// Parse App Store RSS XML (converted to JSON)
const items = [];
const allInputs = $input.all();

for (const input of allInputs) {
  try {
    const xmlData = input.json;

    // Skip empty data or error responses
    if (!xmlData || xmlData.error) {
      continue;
    }

    // Handle XML-converted JSON structure
    let entries = [];

    if (xmlData.feed && xmlData.feed.entry) {
      entries = Array.isArray(xmlData.feed.entry)
        ? xmlData.feed.entry
        : [xmlData.feed.entry];
    } else if (xmlData.entry) {
      entries = Array.isArray(xmlData.entry)
        ? xmlData.entry
        : [xmlData.entry];
    }

    if (entries.length === 0) {
      continue;
    }

    // Extract country code from feed URL
    let country = 'unknown';
    try {
      const feedId = xmlData.feed?.id || '';
      const feedIdStr = typeof feedId === 'string' ? feedId : (feedId['#text'] || feedId._ || String(feedId));
      const match = feedIdStr.match(/itunes\.apple\.com\/([a-z]{2})\/i);
      if (match) {
        country = match[1].toUpperCase();
      }
    } catch (e) {
      country = 'unknown';
    }

    for (const entry of entries) {
      try {
        let reviewId = '';
        if (entry.id) {
          if (typeof entry.id === 'string') {
            reviewId = entry.id;
          } else if (Array.isArray(entry.id)) {
            reviewId = entry.id[0]?.['#text'] || entry.id[0]?._ || entry.id[0] || '';
          } else {
            reviewId = entry.id['#text'] || entry.id._ || entry.id.text || String(entry.id);
          }
        }

        let userName = 'Anonymous';
        if (entry.author) {
          if (typeof entry.author === 'string') {
            userName = entry.author;
          } else if (entry.author.name) {
            const name = entry.author.name;
            userName = typeof name === 'string'
              ? name
              : (name['#text'] || name._ || name.text || 'Anonymous');
          } else if (Array.isArray(entry.author)) {
            const authorObj = entry.author[0];
            if (authorObj && authorObj.name) {
              const name = authorObj.name;
              userName = typeof name === 'string'
                ? name
                : (Array.isArray(name) ? name[0] : (name['#text'] || name._ || 'Anonymous'));
            }
          }
        }

        let rating = 0;
        if (entry['im:rating']) {
          const ratingVal = entry['im:rating'];
          if (typeof ratingVal === 'string') {
            rating = parseInt(ratingVal, 10) || 0;
          } else if (Array.isArray(ratingVal)) {
            rating = parseInt(ratingVal[0], 10) || 0;
          } else {
            rating = parseInt(ratingVal['#text'] || ratingVal._ || ratingVal.text || '0', 10) || 0;
          }
        }

        let content = '';
        if (entry.content) {
          if (typeof entry.content === 'string') {
            content = entry.content;
          } else if (Array.isArray(entry.content)) {
            for (const c of entry.content) {
              if (typeof c === 'string' && c.length > content.length) {
                content = c;
              } else if (c['#text'] && c['#text'].length > content.length) {
                content = c['#text'];
              } else if (c._ && c._.length > content.length) {
                content = c._;
              }
            }
          } else {
            content = entry.content['#text'] || entry.content._ || entry.content.text || '';
          }
        }

        let date = new Date().toISOString();
        const dateField = entry.updated || entry.published;
        if (dateField) {
          if (typeof dateField === 'string') {
            date = dateField;
          } else if (Array.isArray(dateField)) {
            date = dateField[0]?.['#text'] || dateField[0]?._ || dateField[0] || date;
          } else {
            date = dateField['#text'] || dateField._ || dateField.text || date;
          }
        }

        let appVersion = '';
        if (entry['im:version']) {
          const versionVal = entry['im:version'];
          if (typeof versionVal === 'string') {
            appVersion = versionVal;
          } else if (Array.isArray(versionVal)) {
            appVersion = versionVal[0]?.['#text'] || versionVal[0]?._ || String(versionVal[0] || '');
          } else {
            appVersion = versionVal['#text'] || versionVal._ || versionVal.text || '';
          }
        }
        if (!appVersion && entry.version) {
          const versionVal = entry.version;
          appVersion = typeof versionVal === 'string'
            ? versionVal
            : (versionVal['#text'] || versionVal._ || '');
        }

        if (!reviewId || reviewId === '[object Object]') {
          reviewId = `appstore_${country}_${userName}_${new Date(date).getTime()}`;
        }

        if (content && content.trim().length > 0) {
          items.push({
            json: {
              reviewId: String(reviewId),
              userName: String(userName),
              rating: rating,
              content: String(content).trim(),
              date: date,
              source: 'App Store',
              country: country,
              appVersion: String(appVersion),
              platform: 'iOS'
            }
          });
        }
      } catch (entryError) {
        console.error('Failed to parse review:', entryError.message);
        continue;
      }
    }
  } catch (error) {
    console.error('Failed to parse country data:', error.message);
    continue;
  }
}

// Deduplicate by reviewId
const seen = new Set();
const uniqueItems = items.filter(item => {
  const key = item.json.reviewId;
  if (seen.has(key)) {
    return false;
  }
  seen.add(key);
  return true;
});

return uniqueItems.length > 0 ? uniqueItems : [{ json: { noData: true } }];

// Parse merged data with language, countryType, locale, region fields
// HTML cleaning functionality added

const items = [];

const DEFAULT_LANGUAGE = 'unknown';
const DEFAULT_COUNTRY_TYPE = 'unknown';
const DEFAULT_LOCALE = 'unknown';
const DEFAULT_REGION = 'Unknown';
const DEFAULT_COUNTRY = 'Unknown';

const stripHtml = (html) => {
  if (!html || typeof html !== 'string') return html;

  let text = html.replace(/<[^>]*>/g, '');
  text = text.replace(/&nbsp;/g, ' ');
  text = text.replace(/&amp;/g, '&');
  text = text.replace(/&lt;/g, '<');
  text = text.replace(/&gt;/g, '>');
  text = text.replace(/&quot;/g, '"');
  text = text.replace(/&#39;/g, "'");
  text = text.replace(/&apos;/g, "'");
  text = text.replace(/&#(\d+);/g, (match, dec) => String.fromCharCode(dec));
  text = text.replace(/&[a-zA-Z]+;/g, '');
  text = text.replace(/\s+/g, ' ').trim();

  return text;
};

for (const input of $input.all()) {
  const data = input.json;

  let aiResult = {};

  if (data.message?.content) {
    try {
      aiResult = typeof data.message.content === 'object'
        ? data.message.content
        : JSON.parse(data.message.content);
    } catch (e) {
      console.error('Failed to parse AI result JSON:', e.message);
      aiResult = {};
    }
  } else if (data.translation || data.sentiment) {
    aiResult = {
      translation: data.translation,
      sentiment: data.sentiment,
      intent: data.intent,
      feature: data.feature,
      summary: data.summary,
      keywords: data.keywords,
      priority: data.priority
    };
  }

  const reviewId = data.reviewId || `temp_${Date.now()}`;
  const userName = data.userName || 'Anonymous';
  const rating = data.rating ?? 0;
  const content = stripHtml(data.content || '');
  const date = data.date || new Date().toISOString();
  const source = data.source || 'Unknown';
  const appVersion = data.appVersion || data.originalData?.appVersion || 'Unknown';
  const platform = data.platform || data.originalData?.platform || 'Unknown';
  const thumbsUp = data.thumbsUp || data.originalData?.thumbsUp || 0;

  const country = data.country || data.originalData?.country || DEFAULT_COUNTRY;
  const countryType = data.countryType || data.originalData?.countryType || DEFAULT_COUNTRY_TYPE;
  const language = data.language || data.originalData?.language || DEFAULT_LANGUAGE;
  const locale = data.locale || data.originalData?.locale || DEFAULT_LOCALE;
  const region = data.region || data.originalData?.region || DEFAULT_REGION;

  if (!aiResult || Object.keys(aiResult).length === 0) {
    aiResult = {
      translation: content || 'Parsing failed',
      sentiment: rating >= 4 ? 'Positive' : (rating <= 2 ? 'Negative' : 'Neutral'),
      intent: 'Other',
      feature: 'Other',
      summary: 'Parsing failed',
      keywords: [],
      priority: rating <= 2 ? 'High' : 'Medium'
    };
  }

  const sentiment = aiResult.sentiment || 'Neutral';
  const priority = aiResult.priority || 'Medium';
  const cleanTranslation = stripHtml(aiResult.translation || content);
  const cleanSummary = stripHtml(aiResult.summary || 'Not analyzed');

  items.push({
    json: {
      reviewId: reviewId,
      userName: userName,
      rating: rating,
      content: content,
      date: date,
      source: source,
      appVersion: appVersion,
      platform: platform,
      thumbsUp: thumbsUp,
      country: country,
      countryType: countryType,
      language: language,
      locale: locale,
      region: region,
      title: String(cleanSummary).substring(0, 50),
      translation: cleanTranslation,
      sentiment: sentiment,
      intent: aiResult.intent || 'Other',
      feature: aiResult.feature || 'Other',
      keywords: Array.isArray(aiResult.keywords) ? aiResult.keywords : [],
      priority: priority,
      needsAlert: (rating <= 2 || sentiment === 'Urgent' || priority === 'High')
    }
  });
}

return items.length > 0 ? items : [{ json: { error: 'No data', needsAlert: false } }];

