const inputData = $input.all();

if (!inputData || inputData.length === 0) {
  return [{ json: { noData: true, reason: 'No input data' } }];
}

const response = inputData[0].json;

if (!response) {
  return [{ json: { noData: true, reason: 'API response is empty' } }];
