};

const MULTI_COUNTRY_LANGS = [
  'en', 'es', 'fr', 'de', 'pt', 'ar', 'ru', 'it', 'nl', 'ms',
  'ta', 'hi', 'ur', 'te', 'ml', 'mr', 'gu', 'pa', 'ca', 'eu',
  'gl', 'ku', 'ps',
];

function langToCountry(language, region) {
  if (!language) return region || 'Unknown';

  const lang = String(language).trim();
  const baseLang = lang.split('-')[0].toLowerCase();
  if (MULTI_COUNTRY_LANGS.includes(baseLang) || MULTI_COUNTRY_LANGS.includes(lang)) {
    return region || 'Global';
  }

  if (LANG_TO_COUNTRY[lang]) {
    return LANG_TO_COUNTRY[lang];
  }

  if (LANG_TO_COUNTRY[baseLang]) {
    return LANG_TO_COUNTRY[baseLang];
  }

  return region || 'Unknown';
}

const batchLanguageRaw =
  (inputData[0] && inputData[0].json && (inputData[0].json.googlePlayLanguages || inputData[0].json.languages)) ||
  (response && (response.googlePlayLanguages || response.languages)) ||
  '';

const language_batch = Array.isArray(batchLanguageRaw) 
  ? String(batchLanguageRaw[0] || '').trim() 
  : String(batchLanguageRaw).trim();

let reviews = [];
if (response.reviews && Array.isArray(response.reviews)) {
  reviews = response.reviews;
} else if (response.data && Array.isArray(response.data)) {
  reviews = response.data;
} else if (Array.isArray(response)) {
  reviews = response;
}

if (reviews.length === 0) {
  return [{ json: { noData: true, reason: 'No review data' } }];
}

reviews.forEach((review, index) => {
  try {
    const reviewId = review.reviewId || review.id || `gp_${index}_${Date.now()}`;
    const userName = review.userName || review.author || 'Anonymous';
    const rating = parseInt(review.rating || review.score || 0, 10);
    const content = review.reviewText || review.text || review.content || review.comment || '';

    let date = review.reviewDate || review.date || review.published || review.at || new Date().toISOString();
    if (typeof date === 'number') {
      date = new Date(date).toISOString();
    } else if (typeof date === 'string' && !date.includes('T')) {
      try { date = new Date(date).toISOString(); } catch (e) { date = new Date().toISOString(); }
    }

    const appVersion = review.appVersion || review.version || review.app_version || '';
    const locale = String(review.locale || '').trim();
    const language = String(review.language || language_batch || '').trim();
    const region = String(review.region || '').trim();

    const country = langToCountry(language, region);
    const countryType = LANG_TO_COUNTRY[language] || LANG_TO_COUNTRY[language.split('-')[0]] 
      ? 'country' 
      : 'region';

    if (content && content.trim().length > 0) {
      items.push({
        json: {
          reviewId: String(reviewId),
          userName: String(userName),
          rating: rating,
          content: String(content).trim(),
          date: date,
          source: 'Google Play',
          country: String(country),
          countryType: countryType,
          language: String(language),
          locale: String(locale),
          region: String(region),
          appVersion: String(appVersion),
          platform: review.platform || 'Android',
          thumbsUp: parseInt(review.thumbsUp || 0, 10),
        },
      });
    }
  } catch (err) {
    console.error(`Error processing review ${index}:`, err.message);
  }
});

return items.length > 0 ? items : [{ json: { noData: true, reason: 'No valid reviews' } }];

